/* globals console, window, document */

const dataSets = [
	{
		id: '78900',
		label: 'David Lee',
		values: {
			guestName: 'David Lee',
			reservationNumber: 'Y2JKH5G1Z',
			guestArrivalDate: new Date( 2024, 7, 22 ).toLocaleDateString(),
			guestDepartureDate: new Date( 2024, 8, 22 ).toLocaleDateString(),
			numberOfGuests: 2,
			roomType: 'Double Room',
			guestPhoneNumber: '567-890-1234'
		}
	}
];

const additionalMergeFieldsConfig = {
	initialPreviewMode: '78900',
	previewModes: [ '$dataSets' ],
	dataSets
};

window.ClassicEditor
	.create( document.querySelector( '#snippet-merge-fields-variables' ), {
		mergeFields: { ...window.ClassicEditor.defaultConfig.mergeFields, ...additionalMergeFieldsConfig },
		toolbar: {
			items: [ 'insertMergeField' ].concat( window.ClassicEditor.defaultConfig.toolbar.items )
		}
	} )
	.then( editor => {
		window.editor = editor;

		// Prevent showing a warning notification when user is pasting a content from MS Word or Google Docs.
		window.preventPasteFromOfficeNotification = true;
	} )
	.catch( err => {
		console.error( err.stack );
	} );
